## ⚛️ TypeScript in React

TypeScript and React complement each other perfectly — TypeScript ensures that every prop, state, and event handler is correctly typed, eliminating entire categories of runtime errors.

---

## 1️⃣ Typing Component Props

```typescript
// Define props with interface
interface ButtonProps {
  label: string
  onClick: () => void
  variant?: "primary" | "secondary" | "danger"  // Optional with literal union
  disabled?: boolean
  children?: React.ReactNode  // Any valid JSX
}

// Functional component with typed props
const Button: React.FC<ButtonProps> = ({ label, onClick, variant = "primary", disabled }) => {
  return (
    <button
      className={`btn btn-${variant}`}
      onClick={onClick}
      disabled={disabled}
    >
      {label}
    </button>
  )
}
```

**Note:** `React.FC` is optional — typing the function directly is also valid:
```typescript
function Button({ label, onClick }: ButtonProps) { ... }
```

---

## 2️⃣ Typing `useState`

TypeScript can infer simple types, but explicitly type complex ones:

```typescript
// Inference works for simple types
const [count, setCount] = useState(0)       // number
const [name, setName] = useState("")        // string
const [isOpen, setIsOpen] = useState(false) // boolean

// Explicit type needed when initial value is null/undefined
const [user, setUser] = useState<User | null>(null)
const [items, setItems] = useState<string[]>([])
const [error, setError] = useState<string | null>(null)
```

---

## 3️⃣ Typing Event Handlers

```typescript
// Form input change
const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
  setName(e.target.value)
}

// Form submission
const handleSubmit = (e: React.FormEvent<HTMLFormElement>) => {
  e.preventDefault()
  // ...
}

// Button click
const handleClick = (e: React.MouseEvent<HTMLButtonElement>) => {
  e.stopPropagation()
}

// Keyboard event  
const handleKeyDown = (e: React.KeyboardEvent<HTMLInputElement>) => {
  if (e.key === "Enter") submit()
}

// Select change
const handleSelect = (e: React.ChangeEvent<HTMLSelectElement>) => {
  setFilter(e.target.value)
}
```

---

## 4️⃣ Typing `useRef`

```typescript
// Typing a DOM element ref
const inputRef = useRef<HTMLInputElement>(null)
// inputRef.current is HTMLInputElement | null

// Accessing the ref safely
const focusInput = () => {
  inputRef.current?.focus()  // Optional chaining for null safety
}

return <input ref={inputRef} />

// Typing a mutable value ref (not a DOM element)
const countRef = useRef<number>(0)  // Not null — no need for null check
```

---

## 5️⃣ Typing `useContext`

```typescript
interface AuthContext {
  user: User | null
  login: (credentials: Credentials) => Promise<void>
  logout: () => void
}

// Create typed context
const AuthContext = createContext<AuthContext | null>(null)

// Custom hook with null guard
function useAuth(): AuthContext {
  const ctx = useContext(AuthContext)
  if (!ctx) throw new Error("useAuth must be used within AuthProvider")
  return ctx
}

// Provider
function AuthProvider({ children }: { children: React.ReactNode }) {
  const [user, setUser] = useState<User | null>(null)
  // ...
  return (
    <AuthContext.Provider value={{ user, login, logout }}>
      {children}
    </AuthContext.Provider>
  )
}
```

