## 7️⃣ Generic Components

```typescript
// A generic list component
interface ListProps<T> {
  items: T[]
  renderItem: (item: T) => React.ReactNode
  keyExtractor: (item: T) => string
}

function List<T>({ items, renderItem, keyExtractor }: ListProps<T>) {
  return (
    <ul>
      {items.map(item => (
        <li key={keyExtractor(item)}>{renderItem(item)}</li>
      ))}
    </ul>
  )
}

// Usage — TypeScript infers T as User
<List
  items={users}
  renderItem={(user) => <span>{user.name}</span>}
  keyExtractor={(user) => user.id.toString()}
/>
```

---

## 8️⃣ Typing Custom Hooks

```typescript
interface UseFetchResult<T> {
  data: T | null
  loading: boolean
  error: string | null
  refetch: () => void
}

function useFetch<T>(url: string): UseFetchResult<T> {
  const [data, setData] = useState<T | null>(null)
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState<string | null>(null)

  const fetch = async () => {
    try {
      const res = await globalThis.fetch(url)
      const json: T = await res.json()
      setData(json)
    } catch (e) {
      setError((e as Error).message)
    } finally {
      setLoading(false)
    }
  }

  useEffect(() => { fetch() }, [url])
  return { data, loading, error, refetch: fetch }
}

// Usage — TypeScript knows data is User | null
const { data: user, loading } = useFetch<User>("/api/user/1")
```

---

## 9️⃣ `React.ReactNode` vs `React.ReactElement` vs `JSX.Element`

```typescript
React.ReactNode    // Anything React can render: JSX, string, number, null, array
React.ReactElement // A React element (JSX expression result)
JSX.Element        // Alias for React.ReactElement — same thing

// Use ReactNode for children props (most accepting)
interface CardProps {
  children: React.ReactNode  // Can be any renderable content
}
```

---

## 💡 Summary

| Scenario | TypeScript Pattern |
|---|---|
| Component props | `interface Props {}` |
| Optional prop | `name?: string` |
| Children | `children: React.ReactNode` |
| State with nulls | `useState<User | null>(null)` |
| Input change event | `React.ChangeEvent<HTMLInputElement>` |
| Form submit | `React.FormEvent<HTMLFormElement>` |
| DOM ref | `useRef<HTMLDivElement>(null)` |
| Generic component | `function Comp<T>(props: Props<T>)` |
| Typed context | `createContext<Type | null>(null)` |
